import os, json

# Check what files exist in /tmp
files = os.listdir('/tmp')
print('Files in /tmp:')
for f in files:
    if f.endswith('.json'):
        print(f)

# Try to find patient data files
brca_data = None
cdh1_data = None

for fname in files:
    if fname.endswith('.json'):
        try:
            with open(f'/tmp/{fname}', 'r') as f:
                data = json.load(f)
                if len(data) > 0:
                    # Check if this has patient_id and histological_type
                    if 'patient_id' in str(data[0]) and 'histological_type' in str(data[0]):
                        brca_data = data
                        print(f'Found BRCA patients data: {fname} ({len(data)} records)')
                    # Check if this has ParticipantBarcode for CDH1
                    elif 'ParticipantBarcode' in str(data[0]):
                        cdh1_data = data
                        print(f'Found CDH1 mutations data: {fname} ({len(data)} records)')
        except Exception as e:
            print(f'Error reading {fname}: {e}')

if brca_data and cdh1_data:
    print(f'\nSuccess: Loaded {len(brca_data)} BRCA patients and {len(cdh1_data)} CDH1 mutations')
else:
    print('Could not find both required data files')

